// Vulnerable DOM-Based XSS example
// JavaScript reads from URL and writes to page

// URL: https://example.com/page#name=<img src=x onerror=alert('XSS')>

var name = location.hash.split('=')[1];
document.getElementById('welcome').innerHTML = 'Hello ' + name;

// The malicious payload executes when written to innerHTML
// The server never sees or processes the attack payload
// All the vulnerable code runs in the browser

// Safer alternative:
document.getElementById('welcome').textContent = 'Hello ' + name;
// textContent treats input as text, not HTML, preventing script execution

// Basic HSTS header - enforce HTTPS for 1 year
Strict-Transport-Security: max-age=31536000

// HSTS with subdomain inclusion
Strict-Transport-Security: max-age=31536000; includeSubDomains

// HSTS with preload (for submission to browser preload lists)
Strict-Transport-Security: max-age=31536000; includeSubDomains; preload

// Short duration for testing (1 day)
Strict-Transport-Security: max-age=86400

// To disable HSTS (use with caution!)
Strict-Transport-Security: max-age=0

// Prevent all framing - strongest protection
X-Frame-Options: DENY

// Allow framing only from same origin
X-Frame-Options: SAMEORIGIN

// Allow framing from specific site (limited browser support)
X-Frame-Options: ALLOW-FROM https://trusted-site.com

// Modern alternative using CSP frame-ancestors
Content-Security-Policy: frame-ancestors 'none'  // equivalent to DENY
Content-Security-Policy: frame-ancestors 'self'  // equivalent to SAMEORIGIN
Content-Security-Policy: frame-ancestors https://trusted-site.com  // more flexible

// Enable MIME-type sniffing protection
X-Content-Type-Options: nosniff

// This is the only valid value for this header
// No other options exist

// Example with proper Content-Type declaration
Content-Type: image/jpeg
X-Content-Type-Options: nosniff
// Browser will treat this file ONLY as JPEG, never as script

// For scripts
Content-Type: application/javascript
X-Content-Type-Options: nosniff
// Browser will only execute if Content-Type matches

// No referrer information sent
Referrer-Policy: no-referrer

// Send only origin, not full URL
Referrer-Policy: origin

// Send origin only when crossing origins
Referrer-Policy: origin-when-cross-origin

// Recommended: Full URL for same-origin, origin for cross-origin
Referrer-Policy: strict-origin-when-cross-origin

// Full URL always sent (least privacy)
Referrer-Policy: unsafe-url

// Example scenarios:
// User on: https://site.com/user/profile?id=secret
// Clicks link to: https://external.com

// no-referrer → No Referer header sent
// origin → Referer: https://site.com
// strict-origin-when-cross-origin → Referer: https://site.com
// unsafe-url → Referer: https://site.com/user/profile?id=secret

// Block all access to camera and microphone
Permissions-Policy: camera=(), microphone=()

// Allow geolocation only for your site
Permissions-Policy: geolocation=(self)

// Allow specific trusted origins
Permissions-Policy: payment=(self "https://trusted-payment.com")

// Comprehensive policy blocking multiple features
Permissions-Policy: camera=(), microphone=(), geolocation=(), 
  payment=(), usb=(), magnetometer=(), gyroscope=()

// Allow your site for multiple features
Permissions-Policy: camera=(self), microphone=(self), fullscreen=(self)

// Old Feature-Policy syntax (deprecated but still supported)
Feature-Policy: camera 'none'; microphone 'none'

# Apache (.htaccess or httpd.conf)
<IfModule mod_headers.c>
  Header always set Strict-Transport-Security "max-age=31536000; includeSubDomains"
  Header always set X-Frame-Options "DENY"
  Header always set X-Content-Type-Options "nosniff"
  Header always set Referrer-Policy "strict-origin-when-cross-origin"
  Header always set Permissions-Policy "camera=(), microphone=(), geolocation=()"
</IfModule>

# Nginx (nginx.conf or site config)
server {
  add_header Strict-Transport-Security "max-age=31536000; includeSubDomains" always;
  add_header X-Frame-Options "DENY" always;
  add_header X-Content-Type-Options "nosniff" always;
  add_header Referrer-Policy "strict-origin-when-cross-origin" always;
  add_header Permissions-Policy "camera=(), microphone=()" always;
}

